// token's font-size to be computed based on the viewport size. As a result, use\n/// with caution in fixed contexts.\n/// @param {String} $name - The name of the token to get the styles for\n/// @param {Boolean} $fluid [false] - Specify whether to include fluid styles for the\n/// @param {Map} $breakpoints [$grid-breakpoints] - Provide a custom breakpoint map to use\n/// @access public\n/// @group @carbon/type\n@mixin type-style(\n  $name,\n  $fluid: false,\n  $breakpoints: gridconfig.$grid-breakpoints\n) {\n  @if not map.has-key($tokens, $name) {\n    @error 'Unable to find a token with the name: `#{$name}`';\n  }\n\n  $token: map.get($tokens, $name);\n\n  // If $fluid is set to true and the token has breakpoints defined for fluid\n  // styles, delegate to the fluid-type helper for the given token\n  @if $fluid == true and map.has-key($token, 'breakpoints') {\n    @include fluid-type($token, $breakpoints);\n  } @else {\n    @include custom-properties($name, $token);\n  }\n}\n"],sourceRoot:""}]),l.locals={panelViewHeader:"-esm-patient-tests__individual-results-table-tablet__panelViewHeader___Spk+B",flex:"-esm-patient-tests__individual-results-table-tablet__flex___7i55L",productiveHeading02:"-esm-patient-tests__individual-results-table-tablet__productiveHeading02___0oCkS",stickySection:"-esm-patient-tests__individual-results-table-tablet__stickySection___z23oK",headerMargin:"-esm-patient-tests__individual-results-table-tablet__headerMargin___pWNvd",headerMarginTablet:"-esm-patient-tests__individual-results-table-tablet__headerMarginTablet___ubsoc",clearButton:"-esm-patient-tests__individual-results-table-tablet__clearButton___AOg+g",leftSection:"-esm-patient-tests__individual-results-table-tablet__leftSection___gfLav",rightSection:"-esm-patient-tests__individual-results-table-tablet__rightSection___aBFAD",rightSectionHeader:"-esm-patient-tests__individual-results-table-tablet__rightSectionHeader___GCbm7",fullView:"-esm-patient-tests__individual-results-table-tablet_